head.script:
//==================================================================================================================
// id       : fi_204_03_23b
// 이름     : 대차대조표(부서별)
// 경로     : 재무회계/일반회계/결산관리/
// 사용계정 : 내부
// 파라미터 :
//            IN  :
//            OUT :
//
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//            fi_100_02_02p.jsp(회사조회팝업) - 미호출
//            fi_204_03_10p_01.jsp(재무제표상세팝업)
//==================================================================================================================
// 로그인사용자 정보
scwin.vLoginCoCd     =  "";  // 소속 자회사 
scwin.vLoginCoClsCd  =  "";  // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd =  "";  // 사용자소속구분코드 
scwin.privAdmin      =  "";  // 어드민권한
scwin.userId         =  "";  // 사용자ID
scwin.vCoCd          =  "";  // 회사코드
scwin.vCoClsCd       =  "";  // 소속회사종류 : 회계_회사구분('CO035' : 0:동부 EXPRESS)

scwin.vAdminYn       =  "";  // 어드민여부
scwin.userEmpNo      =  "";  // 사용자번호

scwin.isSubCompany = false;


scwin.ed_bizDomCd_hidVal =  "";  // 사업영역
scwin.ed_deptCd_hidVal   =  "";  // 부서


scwin.txtCoClsCd         =  "";  // 회사구분

scwin.txt_closeYm1       =  "";
scwin.txt_compYm1        =  "";
scwin.txt_closeYm3       =  "";
scwin.txt_compYm3        =  "";

scwin.isStarted            = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

scwin.onpageload = function() {

    console.log("====== onpageload ================== v1.01");

    // 회원정보를 json 데이터로 모두 받음
    let memJson = $c.data.getMemInfo();

    // 로그인 정보 추출
    let coCd    = $c.gus.cfIsNull( $c.data.getMemInfo("coCd") ) ? '' : $c.data.getMemInfo("coCd");
    let coClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd") ) ? '' : $c.data.getMemInfo("coClsCd");
    let userHomeClsCd = $c.data.getMemInfo("userHomeClsCd");  // 사용자소속구분코드
    let userId     = $c.data.getMemInfo("userId");
    let privAdmin  = $c.data.getMemInfo("privAdmin");
    let empNo      = $c.data.getMemInfo("empNo");

    scwin.vLoginCoCd     = coCd;
    scwin.vLoginCoClsCd  = coClsCd;
    scwin.vUserHomeClsCd = userHomeClsCd;

    scwin.vCoCd          = coCd;      
    scwin.vCoClsCd       = coClsCd;   
    scwin.userId         = userId;
    scwin.vAdminYn       = privAdmin;
    scwin.userEmpNo      = empNo;

    console.log("▶▶ vLoginCoCd : "+ scwin.vLoginCoCd +"   loginCoClsCd : "+ scwin.vLoginCoClsCd );
    console.log("▶▶ vCoCd      : "+ scwin.vCoCd +"   vCoClsCd : "+ scwin.vCoClsCd );
    console.log("▶▶ userId     : "+ scwin.userId +"   userEmpNo : "+ scwin.userEmpNo);
    console.log("▶▶ vUserHomeClsCd : "+ scwin.vUserHomeClsCd +"   vAdminYn : "+ scwin.vAdminYn);
//    console.log("▶▶ memJson : "+ JSON.stringify(memJson));

    // 공통코드 : onPageLoad 에 위치
    const codeOptions = [
         { grpCd : "CO022", compID : "lc_flag" } // 조회구분
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};


//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    console.log("==-==-== onUdcCompleted");

    // 2025-10-14 : 작성일자 포커스 위치 이동
    $p.setTimeout(function() {

		// f_Header();
		rd_type.setValue("2");  // 조정반영
		lc_flag.setSelectedIndex(0);

		//날짜셋팅
		// ed_closeYm2.text = <%=DDate.getDate().substring(0,6)%>;
		// ed_compYm2.text  = <%=DDate.getPrevMonthDate(DDate.getDate(),12).substring(0,6)%>;

        var today = $c.date.getServerDateTime("yyyyMMdd");
        var bef12mothDay =  $c.date.getDateAddMonthDirection(today, -12, "F");

        ica_closeYm2.setValue( today.substring(0,6) );
		ica_compYm2.setValue(  bef12mothDay.substring(0,6) ); 

		scwin.f_Setting();

		scwin.f_setCompanyInfo();
		ica_closeYm2.focus();

    }, {"delay":50});
};


// @@ ====== 준비 ============================================================================== //

//-------------------------------------------------------------------------
// 날짜셋팅 
//-------------------------------------------------------------------------
scwin.f_Setting = function(){
	var imsi_date1 = ica_closeYm2.getValue().trim() + "01";
	var imsi_date2 = ica_compYm2.getValue().trim() + "01";

	if(imsi_date1.substring(4,6)=="01" || imsi_date1.substring(4,6)=="00"){
		scwin.txt_closeYm1 = imsi_date1.substring(0,4)+"00";
	}else{
		scwin.txt_closeYm1 = imsi_date1.toDate().after(0,-1,0).format("YYYYMM");
	}

	if(imsi_date2.substring(4,6)=="01" || imsi_date2.substring(4,6)=="00"){
		scwin.txt_compYm1 = imsi_date2.substring(0,4)+"00";
	}else{
        console.log(" txt_compYm1 ["+ imsi_date2.toDate().after(0,-1,0).format("YYYYMM") +"]");
		scwin.txt_compYm1 = imsi_date2.toDate().after(0,-1,0).format("YYYYMM");
	}

	scwin.txt_closeYm3 = ica_closeYm2.getValue().substring(0,4);
	scwin.txt_compYm3  = ica_compYm2.getValue().substring(0,4); 

	var closeDate = ica_closeYm2.getValue() + "01";
	var compDate  = ica_compYm2.getValue() + "01";
	// gr_master.ColumnProp('closeYm', 'Name')          = closeDate.toDate().after(0,0,0).format("결산년월 : YYYY년MM월");
	// gr_master.ColumnProp('compYm', 'Name')           = compDate.toDate().after(0,0,0).format("비교년월 : YYYY년MM월");

	var title1 = closeDate.toDate().after(0,0,0).format("결산년월 : YYYY년MM월");
	var title2 = compDate.toDate().after(0,0,0).format("비교년월 : YYYY년MM월");

    gr_master.setHeaderValue("closeYmTitle", title1);
    gr_master.setHeaderValue("compYmTitle", title2);
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {   
    console.log("=== f_setCompanyInfo (자회사 회계 시스템 설정)");

	// 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
	if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD )  {
		scwin.vLoginCoCd    = ACConstants.CO_CD_DONGBU ;
		scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU ;
	}

	ed_coCd.setValue( scwin.vLoginCoCd );
	scwin.f_PopUpCompanyInfo('T'); 

    // KYU_ORDER
	// if('T' == scwin.vAdminYn  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
	// 	$c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_coCd ]);    
	// }else {
	// 	$c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_coCd  ]);   
	// }  
};


// @@ ====== 조회 ============================================================================== //

//-------------------------------------------------------------------------
// 조회(대차대조표(부서별))
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    console.log("====== f_Retrieve ==================");

	// if (!$c.gus.cfValidate([ed_coCd,ica_closeYm2, rd_type, ed_deptCd, ica_compYm2])) {
    let ret = await $c.gus.cfValidate([ed_coCd,ica_closeYm2, rd_type, ed_deptCd, ica_compYm2]);

	if ( !ret ) {
		return ;
	}

	scwin.f_Setting();

	// ds_search.UseChangeInfo = false
	// tr_search.post();

    ds_search.set("closeYm1", scwin.txt_closeYm1);
    ds_search.set("closeYm3", scwin.txt_closeYm3);
    // 부서명은 팝업 UDC 에서 넣음
    ds_search.set("compYm1" , scwin.txt_compYm1);
    ds_search.set("compYm3" , scwin.txt_compYm3);
    ds_search.set("coClsCd" , scwin.txtCoClsCd);

    var dcJSON = ds_search.getJSON();
    console.log("  *** ds_search : "+ JSON.stringify(dcJSON));

    $c.sbm.execute(sbm_search);
};


//-------------------------------------------------------------------------
// 조회(대차대조표(부서별)) submitdone
//-------------------------------------------------------------------------
scwin.sbm_search_submitdone = function (e) {
    console.log("▷▷ sbm_search_submitdone");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    var temp = ds_master.getRowCount();
    ed_totalRows.setValue(temp);
};


// @@ ====== 이벤트 - 팝업 ===================================================================== //

//-------------------------------------------------------------------------
// 회사코드 focus out
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
// <!-- 회사코드 입력시  -->
// <script language=JavaScript for=ed_coCd event=OnKillFocus()> 
// 	txt_coNm.value ='';
// 	f_PopUpCompanyInfo('T');
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 사업영역코드 focus out
//-------------------------------------------------------------------------
scwin.udc_BizDomCd_onblurCodeEvent = function (e) {
// <!-- 사업영역 EMEDIT -->
// language=JavaScript for=ed_BizDomCd event=OnKillFocus()>
	// if (f_IsPopUp(ed_BizDomCd, txt_BizDomNm) == false) return;
	// f_BizDomPopUp();

    scwin.f_IsPopUp(ed_bizDomCd, ed_bizDomNm, '1', 'T');
};

//-------------------------------------------------------------------------
// 부서코드 focus out
//-------------------------------------------------------------------------
scwin.udc_deptCd_onblurCodeEvent = function (e) {
// <!-- 부서 EMEDIT -->
// language=JavaScript for=ed_deptCd event=OnKillFocus()>
	// if (f_IsPopUp(ed_deptCd, txt_deptNm) == false) return;
	// f_deptPopUp();
    scwin.f_IsPopUp(ed_deptCd, ed_deptNm, '2', 'T');
};


// @@ ====== 팝업 ============================================================================== //

//-------------------------------------------------------------------------
// 회사코드 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF )  {
	// var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
	// 							,ed_coCd.text, txt_coNm.value
	// 							,pWinCloseTF,null,null,null,null
	// 							,null,null,null,null,null);   
    // KYU_TEST : 회사코드 코드 null일 때 팝업 안뜨게 처리 : 2026-01-19
    let pNoDataCloseTF = pWinCloseTF;
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue()
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null,null,null,null,pNoDataCloseTF );
};

//-------------------------------------------------------------------------
// 사업영역 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_BizDomCd_onclickEvent = function (e) {
    scwin.f_BizDomPopUp('F');
};

//-------------------------------------------------------------------------
// 사업영역코드팝업
//-------------------------------------------------------------------------
scwin.f_BizDomPopUp = function (check) {
	var paramArray = new Object();
	paramArray.pSelectID = 'retrieveBizDomCdInfo';
	paramArray.pCode = ed_bizDomCd.getValue();
	paramArray.pName = ed_bizDomNm.getValue();
	//paramArray.pW = "410";

	// var rtnList = f_PopUp2(paramArray, '1');
    scwin.f_PopUp2(paramArray, '1', check);
};


//-------------------------------------------------------------------------
// 부서코드 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_deptCd_onclickEvent = function (e) {
    scwin.f_deptPopUp('F');
};

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function(check) {
	var paramArray = new Object();

	paramArray.pSelectID = 'retrieveAcctDeptCdInfo';
	paramArray.pCode = ed_deptCd.getValue();
	paramArray.pName = ed_deptNm.getValue();
	// paramArray.pW = "410";
	paramArray.pWhere = ds_search.get("closeYm1");

	// var rtnList = f_PopUp2(paramArray, '2');
    scwin.f_PopUp2(paramArray, '2', check);
};

//-------------------------------------------------------------------------
// 팝업 @@
//   flag - 1:사업영역,2:부서
//-------------------------------------------------------------------------
scwin.f_PopUp2 = function(paramArray, flag, check) {
    // KYU_NEW : check 추가
    console.log("=== f_PopUp2 ( flag["+flag+"]  check["+check+"]  1:사업영역,2:부서)");

	var codeObj = paramArray.pCode;
	var nameObj = paramArray.pName;

    // console.log(" codeObj ["+codeObj+"]  nameObj ["+nameObj+"]");

	// rtnList = cfCommonPopUp(paramArray.pSelectID, cfGetValue(codeObj), ""
	// 					   ,f_EventCheck(), paramArray.pDispCnt
	// 					   ,paramArray.pTitle, paramArray.pWidth
	// 					   ,paramArray.pHidden, paramArray.pWhere
	// 					   ,paramArray.pW, paramArray.pH
	// 					   ,paramArray.pTop, paramArray.pLeft
	// 					   ,paramArray.pExistTF, paramArray.pAllSearchTF
	// 					   ,paramArray.pWtitleSearch)
    switch (flag){
        case '1':
                // 사업영역
                paramArray.pSelectID = 'retrieveBizDomCdInfo';
                udc_bizDomCd.cfCommonPopUp(scwin.udc_bizDomCd_callBackFunc, ed_bizDomCd.getValue(), ""
						,check  //"F" // ,scwin.f_EventCheck()
                        ,paramArray.pDispCnt
						,paramArray.pTitle, paramArray.pWidth
						,paramArray.pHidden, paramArray.pWhere
						,paramArray.pW, paramArray.pH
						,paramArray.pTop, paramArray.pLeft
						,paramArray.pExistTF, paramArray.pAllSearchTF
						,paramArray.pWtitleSearch);
                break;
        case '2':
                // 부서
                paramArray.pSelectID = 'retrieveAcctDeptCdInfo';
                udc_deptCd.cfCommonPopUp(scwin.udc_deptCd_callBackFunc, ed_deptCd.getValue(), ""
						,check  //"F"  // ,scwin.f_EventCheck()
                        ,paramArray.pDispCnt
						,paramArray.pTitle, paramArray.pWidth
						,paramArray.pHidden, paramArray.pWhere
						,paramArray.pW, paramArray.pH
						,paramArray.pTop, paramArray.pLeft
						,paramArray.pExistTF, paramArray.pAllSearchTF
						,paramArray.pWtitleSearch);
                break;
        default :
                break;
    }
};



// @@ ====== 팝업 callBackFunc ================================================================= //
//   1:사업영역,2:부서

//-------------------------------------------------------------------------
// 회사코드조회 callBackFunc
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function(rtnList) {
    console.log("▲ udc_coCd_callBackFunc (회사코드조회 팝업 callBackFunc)");
    console.log("   rtnList ["+rtnList+"]");

	// SET	 
	if(rtnList != null ) { 
		if (rtnList[0] == "N/A") return;  

		ed_coCd.setValue( rtnList[0] );	// 코드
		ed_coNm.setValue( rtnList[5] ); // 회사명 
		scwin.ed_coCd_hidVal = rtnList[0];  // 히든값
		scwin.txtCoClsCd     = rtnList[1];	// 회사구분    

	}else{
		ed_coCd.setValue( "" );	// 코드
		ed_coNm.setValue( "" ); // 회사명 
		scwin.ed_coCd_hidVal = "";  // 히든값
		scwin.txtCoClsCd     = "";	// 회사구분    
	}

	if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU )  {  	// 자회사 회계 시스템 
		scwin.isSubCompany = true;
	}else{
		scwin.isSubCompany = false;
	}

    if ( scwin.isStarted == true ) {  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)
        console.log("  ==-==-== 자회사 여부에 따른 회사코드팝업 활성/비활성 처리 (최초 1회)");

        // KYU_ORDER
	    if('T' == scwin.vAdminYn  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
		    $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_coCd ]);    
	    }else {
		    $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_coCd  ]);   
	    }
        scwin.isStarted            = false;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)
    }
};


//-------------------------------------------------------------------------
// 사업영역조회 callBackFunc (1)
//-------------------------------------------------------------------------
scwin.udc_bizDomCd_callBackFunc = function(rtnList) {
    console.log("▲ udc_bizDomCd_callBackFunc (사업영역조회 팝업 callBackFunc)");
    console.log("   rtnList ["+rtnList+"]");

    scwin.f_resultPopEd(ed_bizDomCd,ed_bizDomNm,rtnList, '1');
};


//-------------------------------------------------------------------------
// 부서조회 callBackFunc (2)
//-------------------------------------------------------------------------
scwin.udc_deptCd_callBackFunc = function(rtnList) {
    console.log("▲ udc_deptCd_callBackFunc (부서조회 팝업 callBackFunc)");
    console.log("   rtnList ["+rtnList+"]");

    scwin.f_resultPopEd(ed_deptCd,ed_deptNm,rtnList, '2');
};

//-------------------------------------------------------------------------
// 팝업결과
//  flag : 신규 추가. 어떤 팝업을 호출했는지 구분
//  1:사업영역,2:부서
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function(strCd,strNm,rtnList, flag){
    console.log("=== f_resultPopEd (팝업결과)   flag ["+flag+"]  1:사업영역,2:부서)");

	// if (rtnList != null ) {
    // 	if (rtnList[0] != "N/A") {
    // 		cfSetValue(codeObj,rtnList[0]);
	// 		codeObj.hidVal = rtnList[0];
	// 		cfSetValue(nameObj,rtnList[1]);
	// 	}
    // } else {
	// 	cfSetValue(codeObj,"");
	// 	codeObj.hidVal = "";
	// 	cfSetValue(nameObj,"");
    // }
	// return rtnList;

    if (rtnList != null ) {
        if (rtnList[0] == "N/A") {
            // 히든값 분기처리
            switch (flag){
                case '1'  : scwin.ed_bizDomCd_hidVal          = ""; break;  // 사업영역
                case '2'  : scwin.ed_deptCd_hidVal            = ""; break;  // 부서
                default   : break;
            }
            return;
        }
        strCd.setValue(rtnList[0]);    // 코드
        strNm.setValue(rtnList[1]);   // 명

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_bizDomCd_hidVal       = rtnList[0]; break;  // 사업영역
            case '2'  : scwin.ed_deptCd_hidVal         = rtnList[0]; break;  // 부서
            default   : break;
        }
    }else{
	    strCd.setValue( "" );
		strNm.setValue( "" );

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_bizDomCd_hidVal          = ""; break;  // 사업영역
            case '2'  : scwin.ed_deptCd_hidVal            = ""; break;  // 부서
            default   : break;
        }
    }

    // 추가처리 : f_deptPopUp / f_BizDomPopUp 뒤에 있는 처리
    switch (flag){
        case '1':
                // 사업영역
				if (rtnList != null ) {
		// ds_search.NameValue(ds_search.RowPosition,"bizDomCd") = rtnList[0];
		// txt_bizDomNm = rtnList[0];

					ds_search.set("bizDomCd", rtnList[0] );

                    // KYU_TEST : 사업영역명 세팅 변경 - 삭제
					// ed_bizDomNm.setValue( rtnList[0] );
                    ed_bizDomNm.setValue( rtnList[1] );
			    } else {
					ds_search.set("bizDomCd", "");
			    }

                break;
        case '2':
                // 부서
				if (rtnList != null ) {
					ds_search.set("acctDeptLvl", rtnList[6]);
				} else {
					ds_search.set("acctDeptLvl", 0);
				}
                break;
        default :
                break;
    }
};


//-------------------------------------------------------------------------
// 팝업 여부 검사
//  1:사업영역,2:부서
//-------------------------------------------------------------------------
// function f_IsPopUp(inObj) {
scwin.f_IsPopUp = function(strCd, strNm, flag, check)  {
    console.log("=== f_IsPopUp (팝업체크)  srtCd["+strCd+"] strNm["+strNm+"] flag["+flag+"] check["+check+"]");
	// var inValue = cfGetValue(inObj);
	// var hidValue = inObj.hidVal;

    // if (cfIsNull(inValue)) {
    // 	inObj.hidVal = "";
    // 	for (var i=1; i < f_IsPopUp.arguments.length; i++) {
    // 		cfSetValue(f_IsPopUp.arguments[i],"");
    // 	}
    // 	return false;
    // }
    // if (inValue == hidValue) return false;
    // return true;

    // if (strCd.text.trim() == strCd.hidVal) return;
    if ( ( flag=='1'  && (strCd.getValue().trim() == scwin.ed_bizDomCd_hidVal   )) ||  // 사업영역
         ( flag=='2'  && (strCd.getValue().trim() == scwin.ed_deptCd_hidVal     ))     // 부서
        ) {
		// KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
		if ( strCd.getValue() != "" ) return;
    }

    // strNm.value="";

    // 명 초기화
    switch (flag){
        case '1'  : ed_bizDomNm.setValue("");       break;  // 사업영역
        case '2'  : ed_deptNm.setValue("");         break;  // 부서
        default   : break;
    }

    // strCd.hidVal="";

    // 히든값 초기화
    switch (flag){
        case '1'  : scwin.ed_bizDomCd_hidVal          = ""; break;  // 사업영역
        case '2'  : scwin.ed_deptCd_hidVal            = ""; break;  // 부서
        default   : break;
    }

	// 팝업 로딩
    // KYU_NEW
    if(strCd.getValue().trim()!="") {
	    switch (flag){
	        case '1'  : scwin.f_BizDomPopUp(check); break;  // 사업영역
	        case '2'  : scwin.f_deptPopUp(check); break;    // 부서
	        default   : break;
	    }
    }
};


