//-------------------------------------------------------------------------
// 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = async function() {

	if ( ds_master.getTotalRow() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return false;
	}

	//alert(sheetTitle);
	// gr_master.SetExcelTitle(0, "");
	// gr_master.SetExcelTitle(1, "value:"+sheetTitle+";"  // 표시할 타이틀
	// 							    + "font-face:'돋움체';" // 폰트
	// 							    + "font-size:18pt;"    // 폰트 크기
	// 							    + "font-color:black;"  // 폰트 색깔
	// 							    + "bgcolor:#ffffff;"   // 배경 색깔
	// 							    + "align:center;"      // 정렬
	// 							    + "line-color:white;"  // 타이틀 부분 테두리선 색깔
	// 							    + "line-width:0pt;"    // 타이틀 테두리선 굵기
	// 							    + "skiprow:2;");       // 타이틀 다음 떼는 로우 수
	// fileName = '대차대조표_'+".xls";
	// cfGridToExcel(gr_master, fileName, fileName, 8+16);

	var sheetTitle = "대차대조표(부서별)";  // 실제로는 제목
    var fileName   = "대차대조표_";

    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        let options = {
            fileName            : fileName + ".xlsx",
            sheetName           : fileName,
            startRowIndex       : 2,  // 내용 앞으로 몇 row 띄우는지...
            startColumnIndex    : 0,
            bodyWordwrap        : "true"  // 줄바꿈
            // useSubtotal            : "true"  // 소계 출력
        };

        const infoArr = [{
                        rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : 7 /* 병합할 컬럼갯수 */, text : sheetTitle , textAlign : "center", drawBorder: false, fontSize: "18px", fontName: "돋움체"
                    },
                ];

        $c.data.downloadGridViewExcel(gr_master, options, infoArr);
    }
};

